import { readFileSync, writeFileSync } from 'fs';
import { parse } from 'yaml';

const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));

// Combine approved steps (from review-steps) with selected execution config (from review-execution)
const stepsYaml = input.steps?.['generate-steps']?.yaml || input.steps?.['generate-steps']?.raw || '';
const executionConfig = input.steps?.['review-execution'] || {};

const errors = [];

if (!stepsYaml.trim()) {
  errors.push('No workflow steps YAML found');
}

let parsed;
try {
  parsed = parse(stepsYaml);
} catch (err) {
  errors.push(`YAML syntax error: ${err.message}`);
}

if (parsed && typeof parsed === 'object') {
  if (!parsed.name || typeof parsed.name !== 'string') errors.push('Missing or invalid: name (string)');
  if (typeof parsed.version !== 'number') errors.push('Missing or invalid: version (must be integer)');
  if (!Array.isArray(parsed.triggers) || parsed.triggers.length === 0) errors.push('Missing or empty: triggers (array, min 1)');
  if (!Array.isArray(parsed.steps) || parsed.steps.length === 0) errors.push('Missing or empty: steps (array, min 1)');
  if (!Array.isArray(parsed.transitions)) errors.push('Missing: transitions (array)');

  if (Array.isArray(parsed.steps)) {
    const stepIds = parsed.steps.map(s => s.id);
    const terminals = parsed.steps.filter(s => s.type === 'terminal');
    if (terminals.length === 0) errors.push('Must have at least one terminal step');

    parsed.steps.forEach((step, i) => {
      if (!step.id) errors.push(`steps[${i}]: missing id`);
      if (!step.name) errors.push(`steps[${i}]: missing name`);
      if (!step.executor) errors.push(`steps[${i}]: missing executor`);
      if (step.verdicts) {
        Object.entries(step.verdicts).forEach(([k, v]) => {
          if (v.target && !stepIds.includes(v.target)) {
            errors.push(`steps[${i}].verdicts.${k}.target '${v.target}' references unknown step`);
          }
        });
      }
    });

    if (Array.isArray(parsed.transitions)) {
      parsed.transitions.forEach((t, i) => {
        if (!stepIds.includes(t.from)) errors.push(`transitions[${i}].from '${t.from}' references unknown step`);
        if (!stepIds.includes(t.to)) errors.push(`transitions[${i}].to '${t.to}' references unknown step`);
      });
    }
  }
}

writeFileSync('/output/result.json', JSON.stringify({
  valid: errors.length === 0,
  errors,
  workflowDefinition: parsed || null
}));

import { readFileSync, writeFileSync } from 'fs';

const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
const workflowDefinition = input.steps?.['validate']?.workflowDefinition || input.workflowDefinition;

if (!workflowDefinition || !workflowDefinition.name) {
  writeFileSync('/output/result.json', JSON.stringify({
    registered: false,
    error: 'No WorkflowDefinition found in input',
    debugKeys: Object.keys(input)
  }));
  process.exit(0);
}

const baseUrl = process.env.APP_BASE_URL;
const apiKey = process.env.PLATFORM_API_KEY;

if (!baseUrl || !apiKey) {
  writeFileSync('/output/result.json', JSON.stringify({
    registered: false,
    error: 'Missing APP_BASE_URL or PLATFORM_API_KEY environment variables'
  }));
  process.exit(0);
}

try {
  const response = await fetch(`${baseUrl}/api/workflow-definitions`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-Api-Key': apiKey,
    },
    body: JSON.stringify(workflowDefinition),
  });

  const body = await response.json();

  if (response.ok) {
    writeFileSync('/output/result.json', JSON.stringify({
      registered: true,
      name: body.name,
      version: body.version,
      summary: `Workflow '${body.name}' v${body.version} registered successfully`
    }));
  } else {
    writeFileSync('/output/result.json', JSON.stringify({
      registered: false,
      status: response.status,
      error: body.error || 'Registration failed'
    }));
  }
} catch (err) {
  writeFileSync('/output/result.json', JSON.stringify({
    registered: false,
    error: `API call failed: ${err.message}`
  }));
}
